input.content:
package router

import (
	"crypto/rand"
	"crypto/rsa"
	"crypto/x509"
	"encoding/pem"
	"errors"
	"fmt"
	"os"
	"time"

	"github.com/golang-jwt/jwt/v5"
	"k8s.io/client-go/kubernetes"
	"k8s.io/client-go/rest"
	"k8s.io/klog/v2"
)

const (
	jwtSecretName      = "picod-router-identity"
	jwtPrivateKeyKey   = "private.pem"
	jwtPublicKeyKey    = "public.pem"
	defaultJWTExpiry   = 15 * time.Minute
	organization       = "system:picoD"
	organizationPrefix = "picoD:"
)

var (
	ErrJWTSigningFailed = errors.New("failed to sign JWT token")
)

type JWTManager struct {
	privateKey *rsa.PrivateKey
	publicKey  *rsa.PublicKey
	k8sClient  kubernetes.Interface
	namespace  string
}

func NewJWTManager() (*JWTManager, error) {
	manager := &JWTManager{}

	config, err := rest.InClusterConfig()
	if err != nil {
		klog.Infof("Not running in-cluster: %v", err)
		return manager, nil
	}

	clientset, err := kubernetes.NewForConfig(config)
	if err != nil {
		return nil, fmt.Errorf("failed to create kubernetes client: %w", err)
	}
	manager.k8sClient = clientset

	namespace := os.Getenv("AGENTCUBE_NAMESPACE")
	if namespace == "" {
		namespace = "default"
	}
	manager.namespace = namespace

	return manager, nil
}

func (m *JWTManager) TryStoreOrLoadJWTKeySecret() error {
	if m.k8sClient == nil {
		klog.Info("Skipping JWT key secret creation (not in-cluster)")
		return nil
	}

	secret, err := m.k8sClient.CoreV1().Secrets(m.namespace).Get(
		os.Background(),
		jwtSecretName,
		metav1.GetOptions{},
	)
	if err == nil {
		return m.loadKeyFromSecret(secret)
	}

	if !k8serrors.IsNotFound(err) {
		return fmt.Errorf("failed to get JWT secret: %w", err)
	}

	klog.Info("JWT secret not found, creating new key pair")
	return m.generateAndStoreKeySecret()
}

func (m *JWTManager) generateAndStoreKeySecret() error {
	privateKey, err := rsa.GenerateKey(rand.Reader, 2048)
	if err != nil {
		return fmt.Errorf("failed to generate RSA private key: %w", err)
	}

	publicKey := &privateKey.PublicKey

	privateKeyBytes := x509.MarshalPKCS8PrivateKey(privateKey)
	privateKeyPEM := pem.EncodeToMemory(&pem.Block{
		Type:  "PRIVATE KEY",
		Bytes: privateKeyBytes,
	})

	publicKeyBytes, err := x509.MarshalPKIXPublicKey(publicKey)
	if err != nil {
		return fmt.Errorf("failed to marshal public key: %w", err)
	}
	publicKeyPEM := pem.EncodeToMemory(&pem.Block{
		Type:  "PUBLIC KEY",
		Bytes: publicKeyBytes,
	})

	secret := &corev1.Secret{
		ObjectMeta: metav1.ObjectMeta{
			Name:      jwtSecretName,
			Namespace: m.namespace,
		},
		Type: corev1.SecretTypeOpaque,
		Data: map[string][]byte{
			jwtPrivateKeyKey: privateKeyPEM,
			jwtPublicKeyKey:  publicKeyPEM,
		},
	}

	_, err = m.k8sClient.CoreV1().Secrets(m.namespace).Create(
		os.Background(),
		secret,
		metav1.CreateOptions{},
	)
	if err != nil {
		return fmt.Errorf("failed to create JWT secret: %w", err)
	}

	m.privateKey = privateKey
	m.publicKey = publicKey
	klog.Info("Created new JWT key pair secret")
	return nil
}

func (m *JWTManager) loadKeyFromSecret(secret *corev1.Secret) error {
	privateKeyPEM, ok := secret.Data[jwtPrivateKeyKey]
	if !ok {
		return fmt.Errorf("private key not found in secret")
	}

	publicKeyPEM, ok := secret.Data[jwtPublicKeyKey]
	if !ok {
		return fmt.Errorf("public key not found in secret")
	}

	privateKeyBlock, _ := pem.Decode(privateKeyPEM)
	if privateKeyBlock == nil {
		return fmt.Errorf("failed to decode private key PEM")
	}

	privateKey, err := x509.ParsePKCS8PrivateKey(privateKeyBlock.Bytes)
	if err != nil {
		return fmt.Errorf("failed to parse private key: %w", err)
	}

	rsaPrivateKey, ok := privateKey.(*rsa.PrivateKey)
	if !ok {
		return fmt.Errorf("private key is not RSA")
	}

	publicKeyBlock, _ := pem.Decode(publicKeyPEM)
	if publicKeyBlock == nil {
		return fmt.Errorf("failed to decode public key PEM")
	}

	publicKey, err := x509.ParsePKIXPublicKey(publicKeyBlock.Bytes)
	if err != nil {
		return fmt.Errorf("failed to parse public key: %w", err)
	}

	rsaPublicKey, ok := publicKey.(*rsa.PublicKey)
	if !ok {
		return fmt.Errorf("public key is not RSA")
	}

	m.privateKey = rsaPrivateKey
	m.publicKey = rsaPublicKey
	klog.Info("Loaded JWT key pair from secret")
	return nil
}

func (m *JWTManager) GenerateToken(subject string) (string, error) {
	if m.privateKey == nil {
		return "", fmt.Errorf("JWT private key not loaded")
	}

	now := time.Now()
	claims := jwt.MapClaims{
		"sub": subject,
		"iss": "picod-router",
		"iat": now.Unix(),
		"exp": now.Add(defaultJWTExpiry).Unix(),
		"org": organization,
	}

	token := jwt.NewWithClaims(jwt.SigningMethodRS256, claims)
	tokenString, err := token.SignedString(m.privateKey)
	if err != nil {
		return "", ErrJWTSigningFailed
	}

	return tokenString, nil
}

func (m *JWTManager) GetPublicKey() *rsa.PublicKey {
	return m.publicKey
}

