package router

import (
	"context"
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"net/http/httputil"
	"net/url"
	"os"
	"strings"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/volcano-sh/agentcube/pkg/common/types"
	"github.com/volcano-sh/agentcube/pkg/store"
	"k8s.io/klog/v2"
)

const (
	sessionIDHeader        = "x-agentcube-session-id"
	forwardedHostHeader    = "X-Forwarded-Host"
	forwardedProtoHeader   = "X-Forwarded-Proto"
	forwardedForHeader     = "X-Forwarded-For"
	defaultMaxConcurrent   = 1000
	workloadManagerTimeout = 30 * time.Second
)

type SessionManager struct {
	store              store.Store
	workloadManagerURL string
	authToken          string
	jwtManager         *JWTManager
}

func NewSessionManager(store store.Store, workloadManagerURL string, jwtManager *JWTManager) (*SessionManager, error) {
	if workloadManagerURL == "" {
		return nil, fmt.Errorf("WORKLOAD_MANAGER_URL environment variable is not set")
	}

	authToken := ""
	tokenPath := "/var/run/secrets/kubernetes.io/serviceaccount/token"
	if tokenData, err := os.ReadFile(tokenPath); err == nil {
		authToken = strings.TrimSpace(string(tokenData))
	}

	return &SessionManager{
		store:              store,
		workloadManagerURL: strings.TrimSuffix(workloadManagerURL, "/"),
		authToken:          authToken,
		jwtManager:         jwtManager,
	}, nil
}

func (m *SessionManager) GetSandboxBySessionID(ctx context.Context, sessionID, kind string) (*types.SandboxInfo, error) {
	sandbox, err := m.store.GetSandboxBySessionID(ctx, sessionID)
	if err != nil {
		if err == store.ErrNotFound {
			return nil, err
		}
		return nil, err
	}
	return sandbox, nil
}

func (m *SessionManager) CreateSandbox(ctx context.Context, kind, name, namespace string) (*types.SandboxInfo, error) {
	req := &types.CreateSandboxRequest{
		Kind:      kind,
		Name:      name,
		Namespace: namespace,
	}

	reqBody, err := json.Marshal(req)
	if err != nil {
		return nil, err
	}

	createURL := fmt.Sprintf("%s/v1/%s", m.workloadManagerURL, m.getCreatePath(kind))
	httpReq, err := http.NewRequestWithContext(ctx, http.MethodPost, createURL, strings.NewReader(string(reqBody)))
	if err != nil {
		return nil, err
	}

	httpReq.Header.Set("Content-Type", "application/json")
	if m.authToken != "" {
		httpReq.Header.Set("Authorization", "Bearer "+m.authToken)
	}

	client := &http.Client{Timeout: workloadManagerTimeout}
	resp, err := client.Do(httpReq)
	if err != nil {
		return nil, err
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		body, _ := io.ReadAll(resp.Body)
		return nil, fmt.Errorf("workload manager returned status %d: %s", resp.StatusCode, string(body))
	}

	var createResp types.CreateSandboxResponse
	if err := json.NewDecoder(resp.Body).Decode(&createResp); err != nil {
		return nil, err
	}

	if createResp.SessionID == "" {
		return nil, fmt.Errorf("workload manager returned empty session id")
	}

	sandboxInfo := &types.SandboxInfo{
		Kind:        kind,
		SandboxID:   createResp.SandboxID,
		Name:        createResp.SandboxName,
		SessionID:   createResp.SessionID,
		EntryPoints: createResp.EntryPoints,
		CreatedAt:   time.Now(),
	}

	return sandboxInfo, nil
}

func (m *SessionManager) getCreatePath(kind string) string {
	switch kind {
	case types.AgentRuntimeKind:
		return "agent-runtime"
	case types.CodeInterpreterKind:
		return "code-interpreter"
	default:
		return "agent-runtime"
	}
}

func (m *SessionManager) UpdateLastActivity(ctx context.Context, sessionID string) {
	if err := m.store.UpdateSessionLastActivity(ctx, sessionID, time.Now()); err != nil {
		klog.Warningf("Failed to update last activity for session %s: %v", sessionID, err)
	}
}

type SessionRouter struct {
	sessionManager *SessionManager
	maxConcurrent  int
	semaphore      chan struct{}
	jwtManager     *JWTManager
	transport      *http.Transport
}

func NewSessionRouter(sessionManager *SessionManager, jwtManager *JWTManager) *SessionRouter {
	maxConcurrent := defaultMaxConcurrent
	if maxConcurrent <= 0 {
		maxConcurrent = defaultMaxConcurrent
	}

	return &SessionRouter{
		sessionManager: sessionManager,
		maxConcurrent:  maxConcurrent,
		semaphore:      make(chan struct{}, maxConcurrent),
		jwtManager:     jwtManager,
		transport:      &http.Transport{},
	}
}

func (r *SessionRouter) concurrencyMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		select {
		case r.semaphore <- struct{}{}:
			defer func() { <-r.semaphore }()
			c.Next()
		default:
			c.JSON(http.StatusTooManyRequests, gin.H{
				"error": "server overloaded, please try again later",
				"code":  "SERVER_OVERLOADED",
			})
			c.Abort()
			return
		}
	}
}

func (r *SessionRouter) HandleInvoke(c *gin.Context) {
	namespace := c.Param("namespace")
	name := c.Param("name")
	kind := c.Param("kind")
	path := c.Param("path")

	sessionID := c.GetHeader(sessionIDHeader)
	ctx := c.Request.Context()

	var sandbox *types.SandboxInfo
	var err error

	if sessionID == "" {
		sandbox, err = r.sessionManager.CreateSandbox(ctx, kind, name, namespace)
		if err != nil {
			r.handleError(c, err, http.StatusInternalServerError)
			return
		}
		sessionID = sandbox.SessionID
		r.sessionManager.UpdateLastActivity(ctx, sessionID)
	} else {
		sandbox, err = r.sessionManager.GetSandboxBySessionID(ctx, sessionID, kind)
		if err != nil {
			if err == store.ErrNotFound {
				r.handleError(c, fmt.Errorf("session not found: %s", sessionID), http.StatusNotFound)
				return
			}
			r.handleError(c, err, http.StatusInternalServerError)
			return
		}
		r.sessionManager.UpdateLastActivity(ctx, sessionID)
	}

	r.forwardToSandbox(c, sandbox, path, sessionID)
	r.sessionManager.UpdateLastActivity(ctx, sessionID)
}

func (r *SessionRouter) forwardToSandbox(c *gin.Context, sandbox *types.SandboxInfo, path, sessionID string) {
	if len(sandbox.EntryPoints) == 0 {
		c.JSON(http.StatusNotFound, gin.H{
			"error": "no entry point found for sandbox",
		})
		return
	}

	entryPoint := r.selectEntryPoint(sandbox, path)
	if entryPoint == nil {
		c.JSON(http.StatusNotFound, gin.H{
			"error": "no entry point found for sandbox",
		})
		return
	}

	upstreamURL, err := r.buildUpstreamURL(entryPoint)
	if err != nil {
		r.handleError(c, err, http.StatusInternalServerError)
		return
	}

	proxy := httputil.NewSingleHostReverseProxy(upstreamURL)
	proxy.Transport = r.transport

	originalDirector := proxy.Director
	proxy.Director = func(req *http.Request) {
		originalDirector(req)
		req.URL.Path = "/" + strings.TrimPrefix(path, "/")
		req.URL.Host = upstreamURL.Host
		req.Host = upstreamURL.Host

		req.Header.Set(forwardedHostHeader, c.Request.Host)
		if c.Request.TLS != nil {
			req.Header.Set(forwardedProtoHeader, "https")
		} else {
			req.Header.Set(forwardedProtoHeader, "http")
		}

		clientIP := c.ClientIP()
		if existing := req.Header.Get(forwardedForHeader); existing != "" {
			req.Header.Set(forwardedForHeader, existing+", "+clientIP)
		} else {
			req.Header.Set(forwardedForHeader, clientIP)
		}

		if sandbox.Kind == types.SandboxKind || sandbox.Kind == types.SandboxClaimsKind {
			if token, err := r.jwtManager.GenerateToken(sessionID); err == nil {
				req.Header.Set("Authorization", "Bearer "+token)
			} else {
				klog.Errorf("Failed to generate JWT: %v", err)
			}
		}
	}

	proxy.ErrorHandler = func(w http.ResponseWriter, req *http.Request, err error) {
		r.handleProxyError(w, err)
	}

	c.Header(sessionIDHeader, sessionID)
	proxy.ServeHTTP(c.Writer, c.Request)
}

func (r *SessionRouter) selectEntryPoint(sandbox *types.SandboxInfo, path string) *types.SandboxEntryPoint {
	for _, ep := range sandbox.EntryPoints {
		if ep.Path != "" && strings.HasPrefix(path, ep.Path) {
			return &ep
		}
	}
	if len(sandbox.EntryPoints) > 0 {
		return &sandbox.EntryPoints[0]
	}
	return nil
}

func (r *SessionRouter) buildUpstreamURL(entryPoint *types.SandboxEntryPoint) (*url.URL, error) {
	endpoint := entryPoint.Endpoint
	protocol := strings.ToLower(entryPoint.Protocol)

	if !strings.HasPrefix(endpoint, "http://") && !strings.HasPrefix(endpoint, "https://") {
		endpoint = fmt.Sprintf("%s://%s", protocol, endpoint)
	}

	return url.Parse(endpoint)
}

func (r *SessionRouter) handleProxyError(w http.ResponseWriter, err error) {
	errStr := err.Error()
	if strings.Contains(errStr, "connection refused") {
		w.WriteHeader(http.StatusBadGateway)
		json.NewEncoder(w).Encode(gin.H{
			"error": "sandbox unreachable",
		})
		return
	}
	if strings.Contains(errStr, "timeout") {
		w.WriteHeader(http.StatusGatewayTimeout)
		json.NewEncoder(w).Encode(gin.H{
			"error": "sandbox timeout",
		})
		return
	}
	w.WriteHeader(http.StatusBadGateway)
	json.NewEncoder(w).Encode(gin.H{
		"error": "sandbox unreachable",
	})
}

func (r *SessionRouter) handleError(c *gin.Context, err error, statusCode int) {
	c.JSON(statusCode, gin.H{
		"error": err.Error(),
	})
}

func (r *SessionRouter) RegisterRoutes(engine *gin.Engine) {
	v1 := engine.Group("/v1")
	v1.Use(r.concurrencyMiddleware())

	v1.GET("/health/live", r.handleLiveHealth)
	v1.GET("/health/ready", r.handleReadyHealth)

	v1.GET("/namespaces/:namespace/agent-runtimes/:name/invocations/*path", r.HandleInvoke)
	v1.POST("/namespaces/:namespace/agent-runtimes/:name/invocations/*path", r.HandleInvoke)
	v1.GET("/namespaces/:namespace/code-interpreters/:name/invocations/*path", r.HandleInvoke)
	v1.POST("/namespaces/:namespace/code-interpreters/:name/invocations/*path", r.HandleInvoke)
}

func (r *SessionRouter) handleLiveHealth(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{"status": "alive"})
}

func (r *SessionRouter) handleReadyHealth(c *gin.Context) {
	if r.sessionManager == nil {
		c.JSON(http.StatusServiceUnavailable, gin.H{
			"status": "unavailable",
			"error":  "session manager not available",
		})
		return
	}
	c.JSON(http.StatusOK, gin.H{"status": "ready"})
}

package router

import (
	"context"
	"errors"
	"net/http"
	"os/signal"
	"syscall"
	"time"

	"github.com/gin-gonic/gin"
	"golang.org/x/net/http2"
	"golang.org/x/net/http2/h2c"
	"k8s.io/klog/v2"
)

const (
	defaultHTTPPort    = "8080"
	readTimeout        = 30 * time.Second
	idleTimeout        = 90 * time.Second
	shutdownTimeout    = 10 * time.Second
)

var (
	errTLSCertKeyMissing = errors.New("TLS enabled but cert/key not provided")
)

type Config struct {
	Port      string
	EnableTLS bool
	TLSCert   string
	TLSKey    string
}

type Server struct {
	config       *Config
	sessionRouter *SessionRouter
	httpServer   *http.Server
}

func NewServer(config *Config, sessionRouter *SessionRouter) (*Server, error) {
	return &Server{
		config:        config,
		sessionRouter: sessionRouter,
	}, nil
}

func (s *Server) Start() error {
	gin.SetMode(gin.ReleaseMode)
	engine := gin.New()
	engine.Use(gin.Recovery())

	s.sessionRouter.RegisterRoutes(engine)

	s.httpServer = &http.Server{
		Addr:        ":" + s.config.Port,
		Handler:     h2c.NewHandler(engine, &http2.Server{}),
		ReadTimeout: readTimeout,
		IdleTimeout: idleTimeout,
	}

	if s.config.EnableTLS {
		if s.config.TLSCert == "" || s.config.TLSKey == "" {
			return errTLSCertKeyMissing
		}
		return s.httpServer.ListenAndServeTLS(s.config.TLSCert, s.config.TLSKey)
	}

	return s.httpServer.ListenAndServe()
}

func (s *Server) Stop(ctx context.Context) error {
	if s.httpServer != nil {
		shutdownCtx, cancel := context.WithTimeout(ctx, shutdownTimeout)
		defer cancel()
		if err := s.httpServer.Shutdown(shutdownCtx); err != nil {
			klog.Errorf("Error shutting down HTTP server: %v", err)
			return err
		}
	}
	return nil
}

func (s *Server) RunWithGracefulShutdown() error {
	ctx, cancel := signal.NotifyContext(context.Background(), syscall.SIGINT, syscall.SIGTERM)
	defer cancel()

	go func() {
		<-ctx.Done()
		klog.Info("Shutting down router...")
		shutdownCtx, shutdownCancel := context.WithTimeout(context.Background(), shutdownTimeout)
		defer shutdownCancel()
		if err := s.Stop(shutdownCtx); err != nil {
			klog.Errorf("Error stopping router: %v", err)
		}
	}()

	klog.Infof("Starting router on port %s", s.config.Port)
	return s.Start()
}

package main

import (
	"flag"
	"os"

	"github.com/volcano-sh/agentcube/pkg/router"
	"github.com/volcano-sh/agentcube/pkg/store"
	"k8s.io/klog/v2"
)

func main() {
	klog.InitFlags(nil)
	flag.Parse()

	port := flag.String("port", defaultHTTPPort, "API port")
	enableTLS := flag.Bool("enable-tls", false, "Enable TLS")
	tlsCert := flag.String("tls-cert", "", "TLS cert path")
	tlsKey := flag.String("tls-key", "", "TLS key path")

	workloadManagerURL := os.Getenv("WORKLOAD_MANAGER_URL")
	if workloadManagerURL == "" {
		klog.Fatal("WORKLOAD_MANAGER_URL environment variable is not set")
	}

	config := &router.Config{
		Port:      *port,
		EnableTLS: *enableTLS,
		TLSCert:   *tlsCert,
		TLSKey:    *tlsKey,
	}

	jwtManager, err := router.NewJWTManager()
	if err != nil {
		klog.Fatalf("Failed to create JWT manager: %v", err)
	}

	if err := jwtManager.TryStoreOrLoadJWTKeySecret(); err != nil {
		klog.Fatalf("Failed to initialize JWT keys: %v", err)
	}

	storeClient := store.Storage()

	sessionManager, err := router.NewSessionManager(storeClient, workloadManagerURL, jwtManager)
	if err != nil {
		klog.Fatalf("Failed to create session manager: %v", err)
	}

	sessionRouter := router.NewSessionRouter(sessionManager, jwtManager)

	routerServer, err := router.NewServer(config, sessionRouter)
	if err != nil {
		klog.Fatalf("Failed to create router server: %v", err)
	}

	if err := routerServer.RunWithGracefulShutdown(); err != nil {
		klog.Fatalf("Router server failed: %v", err)
	}
}

